 66→export function createAnnotationSettings(overrides = {}) {
 67→  return {
 68→    showWallDimensions: overrides.showWallDimensions ?? true,
 69→    showRoomDimensions: overrides.showRoomDimensions ?? true,
 70→    showOverallDimensions: overrides.showOverallDimensions ?? true,
 71→    showObjectTags: overrides.showObjectTags ?? true,
 72→    showElevationOverallDimensions: overrides.showElevationOverallDimensions ?? true,
 73→    showElevationLevelDimensions: overrides.showElevationLevelDimensions ?? true,
 74→    showElevationOpeningDimensions: overrides.showElevationOpeningDimensions ?? true,
 75→  };
 76→}
