 29→  };
 30→
 31→  if (project.floors.length === 0) {
 32→    project.floors = [createFloor('Ground Floor', 0)];
 33→  }
 34→
 35→  for (const floor of project.floors) {
 36→    if (!floor.id || !Array.isArray(floor.walls)) {
 37→      throw new Error('Invalid floor structure');
 38→    }
 39→  }
 40→
 41→  // Backfill missing room fields for old saves
 42→  project.floors.forEach((floor, index) => {
 43→    if (!floor.name) floor.name = index === 0 ? 'Ground Floor' : `Floor ${index}`;
 44→    if (floor.levelIndex === undefined) {
 45→      floor.levelIndex = floor.level ?? index;
 46→    }
 47→    if (floor.floorToFloorHeight === undefined) {
 48→      floor.floorToFloorHeight = WALL_HEIGHT;
 49→    }
 50→    if (floor.elevation === undefined) {
 51→      floor.elevation = floor.level ?? (floor.levelIndex * floor.floorToFloorHeight);
 52→    }
 53→    delete floor.level;
 54→
 55→    if (!floor.rooms) floor.rooms = [];
 56→    for (const room of floor.rooms) {
 57→      if (!room.points) room.points = [];
 58→      if (room.area === undefined) room.area = 0;
 59→    }
 60→  });
 61→
 62→  // Backfill door/window type fields for old saves
 63→  for (const floor of project.floors) {
 64→    if (!floor.doors) floor.doors = [];
 65→    for (const door of floor.doors) {
 66→      if (!door.type) door.type = 'swing';
 67→      if (door.height === undefined) door.height = DOOR_HEIGHT;
 68→      if (door.sillHeight === undefined) door.sillHeight = DOOR_SILL_HEIGHT;
 69→    }
 70→    if (!floor.windows) floor.windows = [];
 71→    for (const win of floor.windows) {
 72→      if (!win.type) win.type = 'standard';
 73→      if (!win.openDirection) win.openDirection = 'left';
 74→      if (win.height === undefined) win.height = WINDOW_HEIGHT;
 75→      if (win.sillHeight === undefined) win.sillHeight = WINDOW_SILL_HEIGHT;
 76→    }
 77→    if (!floor.columns) floor.columns = [];
 78→    if (!floor.fixtures) floor.fixtures = [];
 79→    if (!floor.beams) floor.beams = [];
 80→    if (!floor.stairs) floor.stairs = [];
 81→    if (!floor.landings) floor.landings = [];
 82→    if (!floor.annotations) floor.annotations = [];
 83→    floor.annotationSettings = createAnnotationSettings(floor.annotationSettings || {});
 84→    // Migrate single slab → slabs array
 85→    if (floor.slab !== undefined) {
 86→      floor.slabs = floor.slab ? [floor.slab] : [];
 87→      delete floor.slab;
 88→    }
 89→    if (!Array.isArray(floor.slabs)) floor.slabs = [];
 90→    // Migrate single sectionCut → sectionCuts array
 91→    if (floor.sectionCut !== undefined) {
 92→      floor.sectionCuts = floor.sectionCut ? [floor.sectionCut] : [];
 93→      delete floor.sectionCut;
 94→    }
 95→    if (!Array.isArray(floor.sectionCuts)) floor.sectionCuts = [];
 96→    for (const wall of floor.walls) {
 97→      if (wall.height === undefined) wall.height = WALL_HEIGHT;
 98→      if (wall.startAttachment === undefined) wall.startAttachment = null;
 99→      if (wall.endAttachment === undefined) wall.endAttachment = null;
100→    }
101→    for (const column of floor.columns) {
102→      if (column.showLabel === undefined) {
103→        column.showLabel = Boolean(column.name);
104→      }
105→    }
106→    for (const fixture of floor.fixtures) {
107→      if (!fixture.fixtureType) fixture.fixtureType = 'kitchenTop';
108→      if (fixture.x === undefined) fixture.x = 0;
109→      if (fixture.y === undefined) fixture.y = 0;
110→      if (fixture.width === undefined) fixture.width = 600;
111→      if (fixture.depth === undefined) fixture.depth = 400;
112→      if (fixture.rotation === undefined) fixture.rotation = 0;
113→      if (fixture.name === undefined) fixture.name = '';
114→    }
115→    for (const beam of floor.beams) {
116→      if (beam.floorLevel === undefined) beam.floorLevel = getFloorElevation(floor, index);
117→    }
118→    for (const stair of floor.stairs) {
119→      if (!stair.startPoint) stair.startPoint = { x: 0, y: 0 };
120→      if (stair.width === undefined) stair.width = STAIR_WIDTH;
121→      if (stair.numberOfRisers === undefined) stair.numberOfRisers = STAIR_RISERS;
122→      if (stair.riserHeight === undefined) stair.riserHeight = STAIR_RISER_HEIGHT;
123→      if (stair.treadDepth === undefined) stair.treadDepth = STAIR_TREAD_DEPTH;
124→      if (stair.direction === undefined) {
125→        stair.direction = { angle: 0 };
126→      } else if (typeof stair.direction === 'number') {
127→        stair.direction = { angle: stair.direction };
128→      } else if (stair.direction.angle === undefined) {
129→        stair.direction.angle = 0;
130→      }
131→      if (stair.floorRelation === undefined) {
132→        stair.floorRelation = { fromFloorId: floor.id, toFloorId: floor.id };
133→      } else {
134→        if (stair.floorRelation.fromFloorId === undefined) stair.floorRelation.fromFloorId = floor.id;
135→        if (stair.floorRelation.toFloorId === undefined) stair.floorRelation.toFloorId = floor.id;
136→      }
137→      if (stair.startLandingAttachment === undefined) stair.startLandingAttachment = null;
138→      if (stair.endLandingAttachment === undefined) stair.endLandingAttachment = null;
139→    }
140→    for (const landing of floor.landings) {
141→      if (!landing.position) landing.position = { x: 0, y: 0 };
142→      if (landing.width === undefined) landing.width = 1000;
143→      if (landing.depth === undefined) landing.depth = 1000;
144→      if (landing.thickness === undefined) landing.thickness = 200;
145→      if (landing.elevation === undefined) landing.elevation = 0;
146→      if (landing.rotation === undefined) landing.rotation = 0;
147→    }
148→    for (const annotation of floor.annotations) {
149→      if (!annotation.id) {
150→        annotation.id = `anno_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
151→      }
152→      if (!annotation.type) annotation.type = 'dimension';
153→      if (!annotation.mode) annotation.mode = 'aligned';
154→      if (!annotation.startPoint) annotation.startPoint = { x: 0, y: 0 };
155→      if (!annotation.endPoint) annotation.endPoint = { x: 0, y: 0 };
156→      if (annotation.offset === undefined) annotation.offset = 300;
157→      if (annotation.textOverride === undefined) annotation.textOverride = '';
158→    }
159→    for (const slab of floor.slabs) {
160→      if (!slab.floorId) slab.floorId = floor.id;
161→      if (!slab.boundaryPoints) slab.boundaryPoints = [];
162→      if (slab.thickness === undefined) slab.thickness = SLAB_THICKNESS;
163→      if (slab.elevation === undefined) slab.elevation = SLAB_ELEVATION;
164→      if (slab.name === undefined) slab.name = '';
165→      if (slab.type === undefined) slab.type = '';
166→    }
167→    for (const sc of floor.sectionCuts) {
168→      if (!sc.id) {
169→        sc.id = `section_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
170→      }
171→      if (!sc.startPoint) sc.startPoint = { x: 0, y: 0 };
172→      if (!sc.endPoint) sc.endPoint = { x: 1000, y: 0 };
173→      if (sc.depth === undefined) sc.depth = 2000;
174→      if (sc.label === undefined) sc.label = 'Section A-A';
175→      if (sc.direction === undefined) sc.direction = 1;
176→    }
177→  }
178→
179→  project.floors = sortFloors(project.floors).map((floor, index) => ({
180→    ...floor,
181→    levelIndex: getFloorLevelIndex(floor, index),
182→    elevation: getFloorElevation(floor, index),
183→    floorToFloorHeight: getFloorToFloorHeight(floor),
184→  }));
185→
186→  for (const sheet of project.sheets) {
187→    if (!sheet.id) {
188→      sheet.id = `sheet_${Math.random().toString(36).slice(2, 8)}`;
189→    }
190→    if (sheet.title === undefined) sheet.title = '';
191→    if (sheet.paperSize === undefined) sheet.paperSize = 'A3_LANDSCAPE';
192→    if (sheet.number === undefined) sheet.number = '';
193→    if (sheet.issueDate === undefined) sheet.issueDate = '';
194→    if (sheet.scaleLabel === undefined) sheet.scaleLabel = '1:100';
195→    if (sheet.scaleMode === undefined) sheet.scaleMode = 'custom';
196→    if (sheet.layoutTemplate === undefined) sheet.layoutTemplate = 'auto';
197→    if (sheet.drawingName === undefined) sheet.drawingName = sheet.title || 'Drawing';
198→    if (sheet.projectNameOverride === undefined) sheet.projectNameOverride = '';
199→    sheet.titleBlock = {
200→      projectTitleOverride: sheet.titleBlock?.projectTitleOverride ?? '',
201→      projectAddressOverride: sheet.titleBlock?.projectAddressOverride ?? '',
202→      drawnBy: sheet.titleBlock?.drawnBy ?? '',
203→      checkedBy: sheet.titleBlock?.checkedBy ?? '',
204→    };
205→    if (!Array.isArray(sheet.revisions)) sheet.revisions = [];
206→    sheet.revisions = sheet.revisions.map((revision) => ({
207→      ...createSheetRevision(),
208→      ...revision,
209→      id: revision?.id || `revision_${sheet.id}_${Math.random().toString(36).slice(2, 8)}`,
210→    }));
211→    if (!Array.isArray(sheet.viewports)) sheet.viewports = [];
212→
213→    for (const viewport of sheet.viewports) {
214→      if (!viewport.id) {
215→        viewport.id = `viewport_${sheet.id}_${Math.random().toString(36).slice(2, 8)}`;
216→      }
217→      if (viewport.sourceView === undefined) viewport.sourceView = 'plan';
218→      if (viewport.sourceFloorId === undefined) viewport.sourceFloorId = getDefaultActiveFloorId(project);
219→      if (viewport.sourceRefId === undefined) viewport.sourceRefId = null;
220→      if (viewport.x === undefined) viewport.x = 20;
221→      if (viewport.y === undefined) viewport.y = 20;
222→      if (viewport.width === undefined) viewport.width = 160;
223→      if (viewport.height === undefined) viewport.height = 100;
224→      if (viewport.scale === undefined) viewport.scale = 100;
225→      if (viewport.title === undefined) viewport.title = '';
226→      if (viewport.rotation === undefined) viewport.rotation = 0;
227→      if (viewport.role === undefined) viewport.role = viewport.sourceView === '3d_preview'
228→        ? 'supplemental'
229→        : (viewport.sourceView === 'plan' ? 'primary' : 'secondary');
230→      if (viewport.captionPosition === undefined) viewport.captionPosition = 'below';
231→      if (viewport.referenceNote === undefined) viewport.referenceNote = '';
232→      if (viewport.lockAutoLayout === undefined) viewport.lockAutoLayout = false;
233→    }
234→  }
235→
236→  return { project, savedAt: json.savedAt };
237→}
