  1→import { WALL_HEIGHT } from './defaults';
  2→import { generateId } from './ids';
  3→import { createAnnotationSettings, createFloor } from './models';
  4→
  5→export const DEFAULT_FLOOR_TO_FLOOR_HEIGHT = WALL_HEIGHT;
  6→
  7→function sortByLevelAndElevation(a, b) {
  8→  const levelIndexDiff = getFloorLevelIndex(a) - getFloorLevelIndex(b);
  9→  if (levelIndexDiff !== 0) return levelIndexDiff;
 10→
 11→  const elevationDiff = getFloorElevation(a) - getFloorElevation(b);
 12→  if (elevationDiff !== 0) return elevationDiff;
 13→
 14→  return (a.name || '').localeCompare(b.name || '');
 15→}
 16→
 17→function clonePoint(point) {
 18→  return point ? { x: point.x, y: point.y } : point;
 19→}
 20→
 21→function cloneAttachment(attachment, columnIdMap) {
 22→  if (!attachment) return null;
 23→
 24→  return {
 25→    ...attachment,
 26→    columnId: attachment.columnId ? (columnIdMap.get(attachment.columnId) || attachment.columnId) : attachment.columnId,
 27→  };
 28→}
 29→
 30→function cloneWall(wall, columnIdMap) {
 31→  return {
 32→    ...wall,
 33→    id: generateId('wall'),
 34→    start: clonePoint(wall.start),
 35→    end: clonePoint(wall.end),
 36→    startAttachment: cloneAttachment(wall.startAttachment, columnIdMap),
 37→    endAttachment: cloneAttachment(wall.endAttachment, columnIdMap),
 38→  };
 39→}
 40→
 41→function cloneRoom(room) {
 42→  return {
 43→    ...room,
 44→    id: generateId('room'),
 45→    points: (room.points || []).map(clonePoint),
 46→    labelPosition: clonePoint(room.labelPosition),
 47→  };
 48→}
 49→
 50→function cloneDoor(door, wallIdMap) {
 51→  return {
 52→    ...door,
 53→    id: generateId('door'),
 54→    wallId: wallIdMap.get(door.wallId) || door.wallId,
 55→  };
 56→}
 57→
 58→function cloneWindow(windowItem, wallIdMap) {
 59→  return {
 60→    ...windowItem,
 61→    id: generateId('win'),
 62→    wallId: wallIdMap.get(windowItem.wallId) || windowItem.wallId,
 63→  };
 64→}
 65→
 66→function cloneColumn(column) {
 67→  return {
 68→    ...column,
 69→    id: generateId('col'),
 70→  };
 71→}
 72→
 73→function cloneBeam(beam, columnIdMap, elevationDelta) {
 74→  return {
 75→    ...beam,
 76→    id: generateId('beam'),
 77→    startRef: beam.startRef
 78→      ? { ...beam.startRef, id: columnIdMap.get(beam.startRef.id) || beam.startRef.id }
 79→      : null,
 80→    endRef: beam.endRef
 81→      ? { ...beam.endRef, id: columnIdMap.get(beam.endRef.id) || beam.endRef.id }
 82→      : null,
 83→    floorLevel: (beam.floorLevel ?? 0) + elevationDelta,
 84→  };
 85→}
 86→
 87→function cloneLanding(landing) {
 88→  return {
 89→    ...landing,
 90→    id: generateId('landing'),
 91→    position: clonePoint(landing.position),
 92→  };
 93→}
 94→
 95→function cloneStair(stair, sourceFloorId, duplicatedFloorId, landingIdMap) {
 96→  return {
 97→    ...stair,
 98→    id: generateId('stair'),
 99→    startPoint: clonePoint(stair.startPoint),
100→    direction: stair.direction ? { ...stair.direction } : { angle: 0 },
101→    floorRelation: {
102→      fromFloorId: stair.floorRelation?.fromFloorId === sourceFloorId ? duplicatedFloorId : (stair.floorRelation?.fromFloorId ?? duplicatedFloorId),
103→      toFloorId: stair.floorRelation?.toFloorId === sourceFloorId ? duplicatedFloorId : (stair.floorRelation?.toFloorId ?? duplicatedFloorId),
104→    },
105→    startLandingAttachment: stair.startLandingAttachment
106→      ? { ...stair.startLandingAttachment, landingId: landingIdMap.get(stair.startLandingAttachment.landingId) || stair.startLandingAttachment.landingId }
107→      : null,
108→    endLandingAttachment: stair.endLandingAttachment
109→      ? { ...stair.endLandingAttachment, landingId: landingIdMap.get(stair.endLandingAttachment.landingId) || stair.endLandingAttachment.landingId }
110→      : null,
111→  };
112→}
113→
114→function cloneAnnotation(annotation) {
115→  return {
116→    ...annotation,
117→    id: generateId('anno'),
118→    startPoint: clonePoint(annotation.startPoint),
119→    endPoint: clonePoint(annotation.endPoint),
120→  };
121→}
122→
123→function cloneSlab(slab, floorId, elevationDelta) {
124→  return {
125→    ...slab,
126→    id: generateId('slab'),
127→    floorId,
128→    boundaryPoints: (slab.boundaryPoints || []).map(clonePoint),
129→    elevation: (slab.elevation ?? 0) + elevationDelta,
130→  };
131→}
132→
133→function cloneSectionCut(sectionCut) {
134→  return {
135→    ...sectionCut,
136→    id: generateId('section'),
137→    startPoint: clonePoint(sectionCut.startPoint),
138→    endPoint: clonePoint(sectionCut.endPoint),
139→  };
140→}
141→
142→export function getDefaultFloorName(levelIndex = 0) {
143→  if (levelIndex === 0) return 'Ground Floor';
144→  if (levelIndex < 0) return `Basement ${Math.abs(levelIndex)}`;
145→  return `Floor ${levelIndex}`;
146→}
147→
148→export function getFloorLevelIndex(floor, fallbackIndex = 0) {
149→  if (!floor) return fallbackIndex;
150→  if (Number.isFinite(floor.levelIndex)) return floor.levelIndex;
151→  if (Number.isFinite(floor.level)) return floor.level;
152→  return fallbackIndex;
153→}
154→
155→export function getFloorToFloorHeight(floor) {
156→  return floor?.floorToFloorHeight ?? DEFAULT_FLOOR_TO_FLOOR_HEIGHT;
157→}
158→
159→export function getFloorElevation(floor, fallbackIndex = 0) {
160→  if (!floor) return 0;
161→  if (Number.isFinite(floor.elevation)) return floor.elevation;
162→  if (Number.isFinite(floor.level)) return floor.level;
163→  return getFloorLevelIndex(floor, fallbackIndex) * getFloorToFloorHeight(floor);
164→}
165→
166→export function getFloorTopElevation(floor, fallbackIndex = 0) {
167→  return getFloorElevation(floor, fallbackIndex) + getFloorToFloorHeight(floor);
168→}
169→
170→export function sortFloors(floors = []) {
171→  return [...floors].sort(sortByLevelAndElevation);
172→}
173→
174→export function getOrderedFloors(projectOrFloors) {
175→  const floors = Array.isArray(projectOrFloors)
176→    ? projectOrFloors
177→    : (projectOrFloors?.floors || []);
178→  return sortFloors(floors);
179→}
180→
181→export function getProjectFloor(project, floorId) {
182→  return (project?.floors || []).find((floor) => floor.id === floorId) || null;
183→}
184→
185→export function resolveProjectFloor(project, preferredFloorId = null) {
186→  const floorId = getDefaultActiveFloorId(project, preferredFloorId);
187→  return getProjectFloor(project, floorId);
188→}
189→
190→export function getDefaultActiveFloorId(project, preferredFloorId = null) {
191→  const orderedFloors = getOrderedFloors(project);
192→  if (!orderedFloors.length) return null;
193→  if (preferredFloorId && orderedFloors.some((floor) => floor.id === preferredFloorId)) {
194→    return preferredFloorId;
195→  }
196→  return orderedFloors[0].id;
197→}
198→
199→export function getFloorStackBounds(projectOrFloors) {
200→  const floors = getOrderedFloors(projectOrFloors);
201→  if (!floors.length) {
202→    return {
203→      minElevation: 0,
204→      maxElevation: DEFAULT_FLOOR_TO_FLOOR_HEIGHT,
205→    };
206→  }
207→
208→  return {
209→    minElevation: Math.min(...floors.map((floor, index) => getFloorElevation(floor, index))),
210→    maxElevation: Math.max(...floors.map((floor, index) => getFloorTopElevation(floor, index))),
211→  };
212→}
213→
214→export function shiftFloorElevationData(floor, deltaElevation = 0) {
215→  if (!deltaElevation) return { ...floor };
216→
217→  return {
218→    ...shiftFloorAbsoluteElements(floor, deltaElevation),
219→    elevation: getFloorElevation(floor) + deltaElevation,
220→  };
221→}
222→
223→export function shiftFloorAbsoluteElements(floor, deltaElevation = 0) {
224→  if (!deltaElevation) return { ...floor };
225→
226→  return {
227→    ...floor,
228→    beams: (floor.beams || []).map((beam) => ({
229→      ...beam,
230→      floorLevel: (beam.floorLevel ?? getFloorElevation(floor)) + deltaElevation,
231→    })),
232→    slabs: (floor.slabs || []).map((slab) => ({
233→      ...slab,
234→      elevation: (slab.elevation ?? getFloorElevation(floor)) + deltaElevation,
235→    })),
236→  };
237→}
238→
239→export function createFloorAboveHighest(existingFloors = []) {
240→  const orderedFloors = sortFloors(existingFloors);
241→  const topFloor = orderedFloors[orderedFloors.length - 1] || null;
242→  const levelIndex = topFloor ? getFloorLevelIndex(topFloor) + 1 : 0;
243→  const floorToFloorHeight = topFloor ? getFloorToFloorHeight(topFloor) : DEFAULT_FLOOR_TO_FLOOR_HEIGHT;
244→  const elevation = topFloor
245→    ? getFloorElevation(topFloor) + getFloorToFloorHeight(topFloor)
246→    : 0;
247→
248→  return createFloor(getDefaultFloorName(levelIndex), levelIndex, {
249→    elevation,
250→    floorToFloorHeight,
251→  });
252→}
253→
254→export function createDuplicatedFloor(sourceFloor) {
255→  if (!sourceFloor) return null;
256→
257→  const sourceFloorId = sourceFloor.id;
258→  const duplicatedFloorId = generateId('floor');
259→  const sourceLevelIndex = getFloorLevelIndex(sourceFloor);
260→  const sourceElevation = getFloorElevation(sourceFloor);
261→  const floorToFloorHeight = getFloorToFloorHeight(sourceFloor);
262→  const duplicatedElevation = sourceElevation + floorToFloorHeight;
263→  const elevationDelta = duplicatedElevation - sourceElevation;
264→
265→  const columns = (sourceFloor.columns || []).map(cloneColumn);
266→  const columnIdMap = new Map((sourceFloor.columns || []).map((column, index) => [column.id, columns[index].id]));
267→
268→  const walls = (sourceFloor.walls || []).map((wall) => cloneWall(wall, columnIdMap));
269→  const wallIdMap = new Map((sourceFloor.walls || []).map((wall, index) => [wall.id, walls[index].id]));
270→
271→  const landings = (sourceFloor.landings || []).map(cloneLanding);
272→  const landingIdMap = new Map((sourceFloor.landings || []).map((landing, index) => [landing.id, landings[index].id]));
273→
274→  return {
275→    id: duplicatedFloorId,
276→    name: getDefaultFloorName(sourceLevelIndex + 1),
277→    levelIndex: sourceLevelIndex + 1,
278→    elevation: duplicatedElevation,
279→    floorToFloorHeight,
280→    walls,
281→    rooms: (sourceFloor.rooms || []).map(cloneRoom),
282→    doors: (sourceFloor.doors || []).map((door) => cloneDoor(door, wallIdMap)),
283→    windows: (sourceFloor.windows || []).map((windowItem) => cloneWindow(windowItem, wallIdMap)),
284→    columns,
285→    beams: (sourceFloor.beams || []).map((beam) => cloneBeam(beam, columnIdMap, elevationDelta)),
286→    stairs: (sourceFloor.stairs || []).map((stair) => cloneStair(stair, sourceFloorId, duplicatedFloorId, landingIdMap)),
287→    landings,
288→    annotations: (sourceFloor.annotations || []).map(cloneAnnotation),
289→    annotationSettings: createAnnotationSettings(sourceFloor.annotationSettings || {}),
290→    slabs: (sourceFloor.slabs || []).map((slab) => cloneSlab(slab, duplicatedFloorId, elevationDelta)),
291→    sectionCuts: (sourceFloor.sectionCuts || []).map(cloneSectionCut),
292→  };
293→}
