 54→export default function SvgCanvas() {
 55→  const svgRef = useRef(null);
 56→  const isPanning = useRef(false);
 57→  const lastPanPos = useRef({ x: 0, y: 0 });
 58→  const spaceHeld = useRef(false);
 59→  const cursorPosRef = useRef({ x: 0, y: 0 });
 60→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 61→
 62→  const { project, dispatch, getFloor } = useProject();
 63→  const editor = useEditor();
 64→  const {
 65→    activeTool, selectedId, selectedType, toolState,
 66→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode, activeSectionCutId,
 67→    regionSelection, pastePreview, maximizedPanel,
 68→    dispatch: editorDispatch,
 69→  } = editor;
 70→
 71→  const floor = getFloor(activeFloorId);
 72→  const {
 73→    copySelection,
 74→    cutSelection,
 75→    beginPaste,
 76→    updatePastePreview,
 77→    cancelPaste,
 78→    placePaste,
 79→    previewContent,
 80→  } = usePlanClipboardController();
 81→
 82→  const tool = useEditorTool({
 83→    activeTool,
 84→    dispatch,
 85→    editorDispatch,
 86→    project,
 87→    getFloor,
 88→    activeFloorId,
 89→    viewport,
 90→    snapEnabled,
 91→    selectedId,
 92→    selectedType,
 93→    toolState,
 94→    viewMode,
 95→  });
 96→
 97→  const getModelPos = useCallback((e) => {
 98→    const rect = svgRef.current.getBoundingClientRect();
 99→    return screenToModel(e.clientX, e.clientY, viewport, rect);
100→  }, [viewport]);
101→
102→  const handleMouseDown = useCallback((e) => {
103→    // Middle mouse or space+left for pan
104→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
105→      isPanning.current = true;
106→      lastPanPos.current = { x: e.clientX, y: e.clientY };
107→      e.preventDefault();
108→      return;
109→    }
110→
111→    const modelPos = getModelPos(e);
112→    if (pastePreview?.active && e.button === 0) {
113→      placePaste(modelPos);
114→      return;
115→    }
116→    tool.onMouseDown(modelPos, e);
117→  }, [getModelPos, pastePreview, placePaste, tool]);
118→
119→  const handleMouseMove = useCallback((e) => {
120→    if (isPanning.current) {
121→      const dx = e.clientX - lastPanPos.current.x;
122→      const dy = e.clientY - lastPanPos.current.y;
123→      editorDispatch({ type: 'PAN', dx, dy });
124→      lastPanPos.current = { x: e.clientX, y: e.clientY };
125→      return;
126→    }
127→
128→    const modelPos = getModelPos(e);
129→    cursorPosRef.current = modelPos;
130→    setCursorPos(modelPos);
131→    if (pastePreview?.active) {
132→      updatePastePreview(modelPos);
133→      return;
134→    }
135→    tool.onMouseMove(modelPos, e);
136→  }, [getModelPos, pastePreview, tool, updatePastePreview, editorDispatch]);
137→
138→  const handleMouseUp = useCallback((e) => {
139→    if (isPanning.current) {
140→      isPanning.current = false;
141→      return;
142→    }
143→    if (pastePreview?.active) return;
144→    const modelPos = getModelPos(e);
145→    tool.onMouseUp(modelPos, e);
146→  }, [getModelPos, pastePreview, tool]);
147→
148→  const handleDoubleClick = useCallback((e) => {
149→    if (pastePreview?.active) return;
150→    const modelPos = getModelPos(e);
151→    tool.onDoubleClick(modelPos, e);
152→  }, [getModelPos, pastePreview, tool]);
153→
154→  const handleWheel = useCallback((e) => {
155→    e.preventDefault();
156→    const rect = svgRef.current.getBoundingClientRect();
157→    const mouseX = e.clientX - rect.left;
158→    const mouseY = e.clientY - rect.top;
159→
160→    const direction = e.deltaY < 0 ? 1 : -1;
161→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
162→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
163→
164→    // Zoom centered on cursor
165→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
166→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
167→
168→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
169→  }, [viewport, editorDispatch]);
