190→    }, 2500);
191→
192→    return () => window.clearTimeout(timer);
193→  }, [statusMessage, editorDispatch]);
194→
195→  useEffect(() => {
196→    const handleKeyDown = (e) => {
197→      if (isTypingTarget(e.target)) return;
198→
199→      if (e.key === ' ') {
200→        spaceHeld.current = true;
201→        e.preventDefault();
202→      }
203→
204→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan') {
