234→            return;
235→          case 'm':
236→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
237→            return;
238→          case 'w':
239→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
240→            return;
241→          case 'b':
242→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
243→            return;
244→          case 't':
245→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
246→            return;
247→          case 'q':
248→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
249→            return;
250→          case 's':
251→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
252→            return;
253→          case 'r':
254→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
255→            return;
256→          case 'd':
257→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
258→            return;
259→          case 'n':
