306→      svg.removeEventListener('wheel', handleWheel);
307→    };
308→  }, [handleWheel]);
309→
310→  const cursor = spaceHeld.current ? 'grab' : pastePreview?.active ? 'copy' : tool.getCursor();
311→  const zoomPercent = Math.round(viewport.zoom * 1000);
312→  const displayedTool = viewMode.startsWith('elevation_') ? 'select' : activeTool;
313→  const isCanvasMaximized = maximizedPanel === 'canvas';
