 695→function applyCanvasStyle(context, style) {
 696→  if (style.fill) {
 697→    context.fillStyle = `rgb(${Math.round(style.fill[0] * 255)}, ${Math.round(style.fill[1] * 255)}, ${Math.round(style.fill[2] * 255)})`;
 698→  }
 699→  if (style.stroke && style.strokeWidth > 0) {
 700→    context.strokeStyle = `rgb(${Math.round(style.stroke[0] * 255)}, ${Math.round(style.stroke[1] * 255)}, ${Math.round(style.stroke[2] * 255)})`;
 701→    context.lineWidth = style.strokeWidth;
 702→    context.lineCap = style.lineCap || 'butt';
 703→    context.lineJoin = style.lineJoin || 'miter';
 704→    context.setLineDash(style.dashArray || []);
 705→  } else {
 706→    context.setLineDash([]);
 707→  }
 708→}
