 794→  context.globalAlpha = style.fillOpacity;
 795→  context.font = `${style.fontWeight} ${style.fontSize}px ${style.fontFamily}`;
 796→  context.textAlign = style.textAnchor === 'middle' ? 'center' : style.textAnchor === 'end' ? 'right' : 'left';
 797→  context.textBaseline = style.dominantBaseline === 'middle' ? 'middle' : 'alphabetic';
 798→
 799→  const lines = getTextLines(element);
 800→  for (const line of lines) {
