 1→import { buildFloorPreviewObjects } from './objectBuilders';
 2→import { getDefaultActiveFloorId, getFloorElevation, getFloorStackBounds, getOrderedFloors } from '@/domain/floorModels';
 3→
 4→function mergeBounds(current, next) {
 5→  if (!next) return current;
 6→  if (!current) return { ...next };
 7→
 8→  return {
 9→    minX: Math.min(current.minX, next.minX),
10→    maxX: Math.max(current.maxX, next.maxX),
11→    minY: Math.min(current.minY, next.minY),
12→    maxY: Math.max(current.maxY, next.maxY),
13→    minElevation: Math.min(current.minElevation, next.minElevation),
14→    maxElevation: Math.max(current.maxElevation, next.maxElevation),
15→  };
16→}
17→
18→function boundsFromObjects(objects = []) {
19→  return objects.reduce((accumulator, objectDescriptor) => (
20→    mergeBounds(accumulator, objectDescriptor.bounds)
21→  ), null);
22→}
23→
24→function createFallbackBounds(stackBounds, activeFloor) {
25→  const level = stackBounds?.minElevation ?? getFloorElevation(activeFloor);
26→  const top = stackBounds?.maxElevation ?? (level + 3000);
27→  return {
28→    minX: -1500,
29→    maxX: 1500,
30→    minY: -1500,
31→    maxY: 1500,
32→    minElevation: level,
33→    maxElevation: top,
34→  };
35→}
36→
37→function createNavigationTarget(bounds, fallbackBounds) {
38→  const source = bounds || fallbackBounds;
39→  return {
40→    x: (source.minX + source.maxX) / 2,
41→    z: (source.minY + source.maxY) / 2,
42→  };
43→}
44→
45→export function buildPreviewScene(project, options = {}) {
46→  const floors = getOrderedFloors(project);
47→  const activeFloorId = getDefaultActiveFloorId(project, options.activeFloorId);
48→  const activeFloor = floors.find((floor) => floor.id === activeFloorId) || null;
49→  const stackBounds = getFloorStackBounds(floors);
50→  const resolvedVisibleFloorIds = options.visibleFloorIds || floors.map((floor) => floor.id);
51→  const visibleFloorIds = new Set(resolvedVisibleFloorIds);
52→
53→  const floorDescriptors = floors.map((floor) => {
54→    const objects = buildFloorPreviewObjects(floor);
55→    return {
56→      floorId: floor.id,
57→      name: floor.name,
58→      elevation: getFloorElevation(floor),
59→      visible: visibleFloorIds.has(floor.id),
60→      objects,
61→      bounds: boundsFromObjects(objects),
62→    };
63→  });
64→
65→  const visibleObjects = floorDescriptors
66→    .filter((floor) => floor.visible)
67→    .flatMap((floor) => floor.objects);
68→  const bounds = boundsFromObjects(visibleObjects) || createFallbackBounds(stackBounds, activeFloor);
69→  const floorsWithNavigationTargets = floorDescriptors.map((floor) => ({
70→    ...floor,
71→    navigationTarget: createNavigationTarget(floor.bounds, bounds),
72→  }));
73→
74→  return {
75→    activeFloorId,
76→    visibleFloorIds: [...visibleFloorIds],
77→    floors: floorsWithNavigationTargets,
78→    bounds,
79→    defaultTarget: {
80→      x: (bounds.minX + bounds.maxX) / 2,
81→      y: (bounds.minElevation + bounds.maxElevation) / 2,
82→      z: (bounds.minY + bounds.maxY) / 2,
83→    },
84→    groundLevel: stackBounds.minElevation,
85→    hasVisibleObjects: visibleObjects.length > 0,
86→  };
87→}
