407→function createFixtureObject(descriptor, materialPalette, isSelected) {
408→  const builder = FIXTURE_BUILDERS[descriptor.fixtureType];
409→  if (!builder) {
410→    return createBoxObject(descriptor, materialPalette, isSelected);
411→  }
412→
413→  const group = new THREE.Group();
414→  const W = descriptor.size.x;
415→  const H = descriptor.size.y;
416→  const D = descriptor.size.z;
417→
418→  builder(group, W, H, D, materialPalette, isSelected);
419→
420→  group.position.copy(planPointToWorld(descriptor.center, descriptor.baseElevation));
421→  group.rotation.y = planAngleToWorldRotation(descriptor.rotation);
422→
423→  return group;
424→}
425→
426→// ── Railing ──
427→
428→function createRailingObject(descriptor, materialPalette, isSelected) {
429→  const group = new THREE.Group();
430→  const { x: length, y: height, z: width } = descriptor.size;
431→  const railingType = descriptor.railingType || 'handrail';
432→  const railHeight = 50; // handrail tube diameter
433→  const postWidth = 30;
434→
435→  if (railingType === 'glass') {
436→    // Top metal rail
437→    addBox(group, 'railing_handrail', length, railHeight, postWidth,
438→      0, height - railHeight / 2, 0, materialPalette, isSelected);
439→    // Bottom metal rail
440→    addBox(group, 'railing_handrail', length, railHeight, postWidth,
441→      0, railHeight / 2, 0, materialPalette, isSelected);
442→    // Glass panel (full height between rails, no outline for clean look)
443→    const glassH = height - railHeight * 2;
444→    const glassGeo = new THREE.BoxGeometry(
445→      Math.max(length, 1), Math.max(glassH, 1), Math.max(width * 0.3, 1)
446→    );
447→    const glassMesh = new THREE.Mesh(glassGeo,
448→      createMeshMaterial(materialPalette, 'railing_glass', isSelected));
449→    glassMesh.position.set(0, height / 2, 0);
450→    glassMesh.castShadow = false;
451→    glassMesh.receiveShadow = true;
452→    group.add(glassMesh);
453→  } else if (railingType === 'guardrail') {
454→    // Solid opaque panel
455→    addBox(group, 'railing_guardrail', length, height, width,
456→      0, height / 2, 0, materialPalette, isSelected);
457→  } else {
458→    // handrail: top rail + vertical balusters
459→    // Top rail
460→    addBox(group, 'railing_handrail', length, railHeight, postWidth,
461→      0, height - railHeight / 2, 0, materialPalette, isSelected);
462→    // Balusters spaced ~300mm apart
463→    const spacing = 300;
464→    const postCount = Math.max(2, Math.floor(length / spacing) + 1);
465→    const actualSpacing = length / (postCount - 1);
466→    for (let i = 0; i < postCount; i++) {
467→      const px = -length / 2 + i * actualSpacing;
468→      addCylinder(group, 'railing_handrail',
469→        postWidth / 2, postWidth / 2, height - railHeight, 8,
470→        px, (height - railHeight) / 2, 0, materialPalette, isSelected);
471→    }
472→  }
473→
474→  // Position and rotate
475→  const center = planPointToWorld(
476→    descriptor.center,
477→    descriptor.baseElevation
478→  );
479→  group.position.copy(center);
480→  group.rotation.y = planAngleToWorldRotation(descriptor.rotation);
481→
482→  return group;
483→}
484→
485→// ── Dispatcher ──
486→
487→function createObjectForDescriptor(descriptor, materialPalette, isSelected) {
488→  if (descriptor.geometry === 'prism') {
489→    return createPrismObject(descriptor, materialPalette, isSelected);
490→  }
491→
492→  if (descriptor.geometry === 'stair') {
493→    return createStairObject(descriptor, materialPalette, isSelected);
494→  }
495→
496→  if (descriptor.geometry === 'window') {
497→    return createWindowObject(descriptor, materialPalette, isSelected);
498→  }
499→
500→  if (descriptor.geometry === 'railing') {
501→    return createRailingObject(descriptor, materialPalette, isSelected);
502→  }
503→
504→  if (descriptor.geometry === 'fixture') {
505→    return createFixtureObject(descriptor, materialPalette, isSelected);
506→  }
507→
508→  return createBoxObject(descriptor, materialPalette, isSelected);
509→}
510→
511→function matchesSelection(descriptor, selection) {
512→  if (!selection?.selectedId || selection.selectedType !== descriptor.kind) return false;
513→  return (descriptor.metadata?.sourceId || descriptor.id) === selection.selectedId;
514→}
515→
516→function assignPreviewMetadata(object, descriptor, floor) {
517→  const previewTarget = {
518→    kind: descriptor.kind,
519→    sourceId: descriptor.metadata?.sourceId || descriptor.id,
520→    floorId: descriptor.metadata?.floorId || floor.floorId,
521→  };
522→
523→  object.traverse((node) => {
524→    node.userData = {
525→      ...node.userData,
526→      previewTarget,
527→    };
528→  });
529→}
530→
531→export function buildPreviewObjectRoot(sceneDescriptor, materialPalette, selection = null) {
532→  const root = new THREE.Group();
533→  root.name = 'preview-root';
534→
535→  for (const floor of sceneDescriptor.floors) {
536→    const floorGroup = new THREE.Group();
537→    floorGroup.name = `floor-${floor.floorId}`;
538→    floorGroup.visible = floor.visible;
539→    floorGroup.userData = {
540→      floorId: floor.floorId,
541→      floorName: floor.name,
542→      elevation: floor.elevation,
543→    };
544→
545→    for (const descriptor of floor.objects) {
546→      const isSelected = matchesSelection(descriptor, selection);
547→      const object = createObjectForDescriptor(descriptor, materialPalette, isSelected);
548→      object.name = descriptor.id;
549→      object.userData = {
550→        id: descriptor.id,
551→        kind: descriptor.kind,
552→        metadata: descriptor.metadata,
553→      };
554→      assignPreviewMetadata(object, descriptor, floor);
555→      floorGroup.add(object);
556→    }
557→
558→    root.add(floorGroup);
559→  }
560→
561→  return root;
562→}
