 50→export function nextSectionLabel(existingCuts = []) {
 51→  const usedLetters = new Set(
 52→    existingCuts
 53→      .map(c => {
 54→        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 55→        return match ? match[1] : null;
 56→      })
 57→      .filter(Boolean)
 58→  );
 59→  for (let i = 0; i < 26; i++) {
 60→    const letter = String.fromCharCode(65 + i);
 61→    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 62→  }
 63→  return `Section ${existingCuts.length + 1}`;
 64→}
