540→
541→    case 'FLOOR_REPLACE':
542→      return updateFloor(state, action.floorId, () => ({
543→        ...action.floor,
544→      }), true, { sort: true });
545→
546→    case 'FIXTURE_ADD':
547→      return updateFloor(state, action.floorId, f => ({
