566→      }));
567→    case 'COLUMN_DUPLICATE':
568→      return updateFloor(state, action.floorId, f => ({
569→        ...f,
570→        columns: [...(f.columns || []), action.column],
571→      }));
572→    case 'COLUMN_UPDATE':
573→      return updateFloor(state, action.floorId, f => {
574→        const nextColumns = (f.columns || []).map(c => (
575→          c.id === action.column.id ? { ...c, ...action.column } : c
576→        ));
577→        return {
578→          ...f,
579→          columns: nextColumns,
580→          walls: f.walls.map(w => syncWallAttachmentPoints(w, nextColumns)),
581→        };
582→      });
583→    case 'COLUMN_DELETE':
584→      return updateFloor(state, action.floorId, f => ({
585→        ...f,
586→        columns: (f.columns || []).filter(c => c.id !== action.columnId),
587→        walls: f.walls.map(w => detachColumnAttachments(w, f.columns || [], action.columnId)),
588→        beams: (f.beams || []).filter(beam => (
589→          beam.startRef?.id !== action.columnId && beam.endRef?.id !== action.columnId
590→        )),
591→      }));
592→
593→    case 'MARK_SAVED':
594→      return {
595→        ...state,
596→        isDirty: false,
597→        lastSavedAt: new Date().toISOString(),
598→        savedSnapshot: snapshotProject(state.project),
599→      };
600→
601→    case 'UNDO': {
602→      if (state.history.length === 0) return state;
603→      const previousProject = state.history[state.history.length - 1];
604→      return {
605→        ...state,
606→        project: previousProject,
607→        history: state.history.slice(0, -1),
608→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
609→        isDirty: snapshotProject(previousProject) !== state.savedSnapshot,
610→      };
611→    }
612→
613→    case 'REDO': {
614→      if (state.future.length === 0) return state;
615→      const nextProject = state.future[0];
616→      return {
617→        ...state,
618→        project: nextProject,
619→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
620→        future: state.future.slice(1),
621→        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
622→      };
623→    }
624→
625→    default:
626→      return state;
627→  }
628→}
