242→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
243→            return;
244→          case 't':
245→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
246→            return;
247→          case 'q':
248→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
249→            return;
250→          case 's':
251→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
252→            return;
253→          case 'r':
254→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
255→            return;
256→          case 'd':
257→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
258→            return;
259→          case 'n':
260→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
261→            return;
262→          case 'c':
263→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
264→            return;
265→          case 'l':
266→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.LANDING });
267→            return;
268→          case 'h':
269→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.RAILING });
270→            return;
