273→            editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType: 'kitchenTop', previewRotation: 0 } });
274→            return;
275→        }
276→      }
277→
278→      tool.onKeyDown(e);
279→    };
280→
281→    const handleKeyUp = (e) => {
282→      if (isTypingTarget(e.target)) return;
283→
284→      if (e.key === ' ') {
285→        spaceHeld.current = false;
286→      }
287→    };
288→
289→    window.addEventListener('keydown', handleKeyDown);
290→    window.addEventListener('keyup', handleKeyUp);
291→    return () => {
292→      window.removeEventListener('keydown', handleKeyDown);
293→      window.removeEventListener('keyup', handleKeyUp);
294→    };
