394→                {getColumnListLabel(column, floor.columns || [])}
395→              </div>
396→            ))}
397→          </Section>
398→
399→          <Section
400→            title="Rooms"
401→            count={floor.rooms.length}
402→            collapsed={collapsedSections.rooms}
403→            onToggle={() => toggleSection('rooms')}
404→          >
405→            {floor.rooms.map(r => (
406→              <div
407→                key={r.id}
408→                className={`${styles.item} ${selectedId === r.id ? styles.itemSelected : ''}`}
409→                onClick={() => selectObject(r.id, 'room')}
410→              >
411→                {r.name}
412→              </div>
413→            ))}
414→          </Section>
415→        </>
416→      )}
417→    </div>
418→  );
419→}
