  5→import { segmentIntersection } from '@/geometry/line';
  6→import { pointInPolygon } from '@/geometry/polygon';
  7→import { projectPointToSectionCut, sectionCutLength } from '@/geometry/sectionCutGeometry';
  8→import { getStairRenderData, stairTotalRise } from '@/geometry/stairGeometry';
  9→import { doorOutlineOnWall, windowOutlineOnWall } from '@/geometry/wallGeometry';
 10→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
