 13→const EPSILON = 1e-6;
 14→
 15→function clamp(value, min, max) {
 16→  return Math.max(min, Math.min(max, value));
 17→}
 18→
 19→function uniqueSortedValues(values = []) {
 20→  const sorted = [...values].sort((a, b) => a - b);
 21→  return sorted.filter((value, index) => (
 22→    index === 0 || Math.abs(value - sorted[index - 1]) > 1e-4
 23→  ));
 24→}
 25→
 26→function intervalFromValues(values, maxLength) {
 27→  if (!values.length) return null;
 28→  const clamped = values
 29→    .map((value) => clamp(value, 0, maxLength))
 30→    .filter((value) => value >= -EPSILON && value <= maxLength + EPSILON);
 31→  if (!clamped.length) return null;
 32→
 33→  const left = Math.min(...clamped);
 34→  const right = Math.max(...clamped);
 35→  if (right - left < EPSILON) return null;
 36→  return { left, right };
 37→}
 38→
 39→function projectPolygon(sectionCut, polygon = []) {
 40→  return polygon.map((point) => projectPointToSectionCut(sectionCut, point));
 41→}
 42→
 43→function polygonCutInterval(sectionCut, polygon = []) {
 44→  if (polygon.length < 3) return null;
 45→
 46→  const values = [];
 47→  for (let index = 0; index < polygon.length; index += 1) {
 48→    const start = polygon[index];
 49→    const end = polygon[(index + 1) % polygon.length];
 50→    const hit = segmentIntersection(sectionCut.startPoint, sectionCut.endPoint, start, end);
 51→    if (hit) {
 52→      values.push(projectPointToSectionCut(sectionCut, hit).along);
 53→    }
 54→  }
 55→
 56→  if (pointInPolygon(sectionCut.startPoint, polygon)) values.push(0);
 57→  if (pointInPolygon(sectionCut.endPoint, polygon)) values.push(sectionCutLength(sectionCut));
 58→
 59→  return intervalFromValues(uniqueSortedValues(values), sectionCutLength(sectionCut));
 60→}
 61→
 62→function polygonProjectionInfo(sectionCut, polygon = [], depth) {
 63→  if (polygon.length < 3) return null;
 64→  const projected = projectPolygon(sectionCut, polygon);
 65→  const alongs = projected.map((entry) => entry.along);
 66→  const offsets = projected.map((entry) => entry.offset);
 67→  const minOffset = Math.min(...offsets);
 68→  const maxOffset = Math.max(...offsets);
 69→
 70→  if (maxOffset < -EPSILON || minOffset > depth + EPSILON) return null;
 71→
 72→  return {
 73→    interval: intervalFromValues(alongs, sectionCutLength(sectionCut)),
 74→    depth: offsets.reduce((sum, value) => sum + Math.max(0, value), 0) / Math.max(1, offsets.length),
 75→    minOffset,
 76→    maxOffset,
 77→  };
 78→}
 79→
 80→function createSceneRect(id, category, renderMode, interval, bottom, top, depth, sourceId) {
 81→  if (!interval) return null;
 82→  if (interval.right - interval.left < EPSILON) return null;
 83→  if (Math.abs(top - bottom) < EPSILON) return null;
 84→
 85→  return {
 86→    id,
 87→    category,
 88→    renderMode,
 89→    left: interval.left,
 90→    right: interval.right,
 91→    bottom,
 92→    top,
 93→    depth,
 94→    sourceId,
 95→  };
 96→}
 97→
 98→function createFootprintRect(id, category, sourceId, sectionCut, polygon, bottom, top, depthLimit) {
 99→  const cutInterval = polygonCutInterval(sectionCut, polygon);
100→  if (cutInterval) {
101→    return createSceneRect(id, category, 'cut', cutInterval, bottom, top, 0, sourceId);
102→  }
103→
104→  const projection = polygonProjectionInfo(sectionCut, polygon, depthLimit);
105→  if (!projection?.interval) return null;
106→  return createSceneRect(id, category, 'projection', projection.interval, bottom, top, projection.depth, sourceId);
107→}
108→
109→function buildWallElements(floor, sectionCut) {
110→  const floorElevation = getFloorElevation(floor);
111→  return (floor.walls || [])
112→    .map((wall) => {
113→      const outline = getWallRenderData(wall, floor.columns || []).outline;
114→      return createFootprintRect(
115→        `section-wall-${wall.id}`,
116→        'wall',
117→        wall.id,
118→        sectionCut,
119→        outline,
120→        floorElevation,
121→        floorElevation + (wall.height ?? 0),
122→        sectionCut.depth
123→      );
124→    })
125→    .filter(Boolean);
126→}
127→
128→function buildSlabElements(floor, sectionCut) {
129→  return (floor.slabs || [])
130→    .filter(slab => slab.boundaryPoints?.length)
131→    .map(slab => createFootprintRect(
132→      `section-slab-${slab.id}`,
133→      'slab',
134→      slab.id,
135→      sectionCut,
136→      slab.boundaryPoints,
137→      getSlabBottomLevel(slab),
138→      getSlabTopLevel(slab),
139→      sectionCut.depth
140→    ))
141→    .filter(Boolean);
142→}
143→
144→function buildColumnElements(floor, sectionCut) {
145→  const floorElevation = getFloorElevation(floor);
146→  return (floor.columns || [])
147→    .map((column) => createFootprintRect(
148→      `section-column-${column.id}`,
149→      'column',
150→      column.id,
151→      sectionCut,
152→      columnOutline(column),
153→      floorElevation,
154→      floorElevation + column.height,
155→      sectionCut.depth
156→    ))
157→    .filter(Boolean);
158→}
159→
160→function buildBeamElements(floor, sectionCut) {
161→  return (floor.beams || [])
162→    .map((beam) => {
163→      const renderData = getBeamRenderData(beam, floor.columns || []);
164→      if (!renderData) return null;
165→      return createFootprintRect(
166→        `section-beam-${beam.id}`,
167→        'beam',
168→        beam.id,
169→        sectionCut,
170→        renderData.outline,
171→        beam.floorLevel - beam.depth,
172→        beam.floorLevel,
173→        sectionCut.depth
174→      );
175→    })
176→    .filter(Boolean);
177→}
178→
179→function buildDoorElements(floor, sectionCut) {
180→  const floorElevation = getFloorElevation(floor);
181→  return (floor.doors || [])
182→    .map((door) => {
183→      const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
184→      if (!wall) return null;
185→      const info = doorOutlineOnWall(wall, door);
186→      return createFootprintRect(
187→        `section-door-${door.id}`,
188→        'door',
189→        door.id,
190→        sectionCut,
191→        [info.p1, info.p2, info.p3, info.p4],
192→        floorElevation + (door.sillHeight ?? 0),
193→        floorElevation + (door.sillHeight ?? 0) + (door.height ?? 0),
194→        sectionCut.depth
195→      );
196→    })
197→    .filter(Boolean);
198→}
199→
200→function buildWindowElements(floor, sectionCut) {
201→  const floorElevation = getFloorElevation(floor);
202→  return (floor.windows || [])
203→    .map((windowItem) => {
204→      const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
205→      if (!wall) return null;
206→      const info = windowOutlineOnWall(wall, windowItem);
207→      return createFootprintRect(
208→        `section-window-${windowItem.id}`,
209→        'window',
210→        windowItem.id,
211→        sectionCut,
212→        [info.p1, info.p2, info.p3, info.p4],
213→        floorElevation + (windowItem.sillHeight ?? 0),
214→        floorElevation + (windowItem.sillHeight ?? 0) + (windowItem.height ?? 0),
215→        sectionCut.depth
216→      );
217→    })
218→    .filter(Boolean);
219→}
220→
221→function buildStairElements(floor, sectionCut, landingElevationMap) {
222→  const floorElevation = getFloorElevation(floor);
223→  return (floor.stairs || [])
224→    .map((stair) => {
225→      const renderData = getStairRenderData(stair);
226→      if (!renderData) return null;
227→
228→      const cutInterval = polygonCutInterval(sectionCut, renderData.outline);
229→      const projection = polygonProjectionInfo(sectionCut, renderData.outline, sectionCut.depth);
230→      const interval = cutInterval || projection?.interval;
231→      if (!interval) return null;
232→
233→      const startProjection = projectPointToSectionCut(sectionCut, renderData.startPoint);
234→      const endProjection = projectPointToSectionCut(sectionCut, renderData.endPoint);
235→      const clampedStart = clamp(startProjection.along, 0, sectionCutLength(sectionCut));
236→      const clampedEnd = clamp(endProjection.along, 0, sectionCutLength(sectionCut));
237→      if (Math.abs(clampedEnd - clampedStart) < EPSILON) return null;
238→
239→      let baseElevation = floorElevation;
240→      if (stair.startLandingAttachment) {
241→        const elev = landingElevationMap?.get(stair.startLandingAttachment.landingId);
242→        if (elev != null) {
243→          baseElevation = floorElevation + elev;
244→        }
245→      }
246→
247→      const risers = Math.max(1, stair.numberOfRisers || 1);
248→      const rise = stairTotalRise(stair);
249→      const risePerRiser = rise / risers;
250→      const alongStep = (clampedEnd - clampedStart) / risers;
251→      const points = [{ x: clampedStart, z: baseElevation }];
252→      let currentAlong = clampedStart;
253→      let currentZ = baseElevation;
254→
255→      for (let index = 0; index < risers; index += 1) {
256→        currentAlong += alongStep;
257→        points.push({ x: currentAlong, z: currentZ });
258→        currentZ += risePerRiser;
259→        points.push({ x: currentAlong, z: currentZ });
260→      }
261→
262→      return {
263→        id: `section-stair-${stair.id}`,
264→        category: 'stair',
265→        renderMode: cutInterval ? 'cut' : 'projection',
266→        points,
267→        depth: projection?.depth ?? 0,
268→        sourceId: stair.id,
269→      };
270→    })
271→    .filter(Boolean);
272→}
273→
274→function computeSceneBounds(rects, stairs, sectionCut, baseLevel) {
275→  const stairXs = stairs.flatMap((element) => element.points.map((point) => point.x));
276→  const stairZs = stairs.flatMap((element) => element.points.map((point) => point.z));
277→  const rectXs = rects.flatMap((element) => [element.left, element.right]);
278→  const rectZs = rects.flatMap((element) => [element.bottom, element.top]);
279→  const xs = [...rectXs, ...stairXs];
280→  const zs = [...rectZs, ...stairZs];
281→
282→  if (!xs.length || !zs.length) {
283→    return {
284→      minX: 0,
285→      maxX: sectionCutLength(sectionCut) || 3000,
286→      minZ: baseLevel,
287→      maxZ: baseLevel + 3000,
288→    };
289→  }
290→
291→  return {
292→    minX: Math.min(...xs),
293→    maxX: Math.max(...xs),
294→    minZ: Math.min(baseLevel, ...zs),
295→    maxZ: Math.max(...zs),
296→  };
297→}
298→
299→function resolveLandingElevation(landing, stairs, floorLevel) {
300→  if (landing.elevation) return landing.elevation;
301→  return computeLandingElevation(landing, stairs, floorLevel) - floorLevel;
302→}
303→
304→function buildFloorSectionElements(floor, sectionCut) {
305→  const floorElevation = getFloorElevation(floor);
306→  const landings = floor.landings || [];
307→  const stairs = floor.stairs || [];
308→
309→  const landingElevationMap = new Map(
310→    landings.map(l => [l.id, resolveLandingElevation(l, stairs, floorElevation)])
311→  );
312→
313→  return {
314→    rectElements: [
315→      ...buildWallElements(floor, sectionCut),
316→      ...buildSlabElements(floor, sectionCut),
317→      ...buildColumnElements(floor, sectionCut),
318→      ...buildBeamElements(floor, sectionCut),
319→      ...buildDoorElements(floor, sectionCut),
320→      ...buildWindowElements(floor, sectionCut),
321→    ],
322→    stairElements: buildStairElements(floor, sectionCut, landingElevationMap),
323→  };
324→}
325→
326→function buildSectionSceneFromFloors(floors, sectionCut, title = null) {
327→  if (!sectionCut) return null;
328→
329→  const stackBounds = getFloorStackBounds(floors);
330→  const rectElements = [];
331→  const stairElements = [];
332→
333→  for (const floor of floors) {
334→    const floorElements = buildFloorSectionElements(floor, sectionCut);
335→    rectElements.push(...floorElements.rectElements);
336→    stairElements.push(...floorElements.stairElements);
337→  }
338→
339→  const sortedRectElements = rectElements.sort((a, b) => {
340→    if (a.renderMode !== b.renderMode) return a.renderMode === 'projection' ? -1 : 1;
341→    return b.depth - a.depth;
342→  });
343→
344→  const sortedStairElements = stairElements.sort((a, b) => {
345→    if (a.renderMode !== b.renderMode) return a.renderMode === 'projection' ? -1 : 1;
346→    return b.depth - a.depth;
347→  });
348→
349→  return {
350→    viewKey: 'section_view',
351→    title: title || sectionCut.label || 'Section',
352→    rectElements: sortedRectElements,
353→    stairElements: sortedStairElements,
354→    bounds: computeSceneBounds(sortedRectElements, sortedStairElements, sectionCut, stackBounds.minElevation),
355→    groundLevel: stackBounds.minElevation,
356→  };
357→}
358→
359→export function buildSectionScene(floor, sectionCut) {
360→  if (!floor || !sectionCut) return null;
361→  return buildSectionSceneFromFloors([floor], sectionCut, sectionCut.label || 'Section');
362→}
363→
364→export function buildProjectSectionScene(project, sourceFloorId, sectionCutId = null) {
365→  const sourceFloor = resolveProjectFloor(project, sourceFloorId);
366→  if (!sourceFloor) return null;
367→
368→  const cuts = sourceFloor.sectionCuts || [];
369→  const sectionCut = sectionCutId
370→    ? cuts.find((entry) => entry.id === sectionCutId)
371→    : cuts[0] || null;
372→  if (!sectionCut) return null;
373→
374→  return buildSectionSceneFromFloors(
375→    getOrderedFloors(project),
376→    sectionCut,
377→    sectionCut.label || 'Section'
378→  );
379→}
