 15→const PLAN_PADDING = 1500;
 16→const VERTICAL_PADDING = 700;
 17→const TOP_PADDING = 1100;
 18→
 19→function boundsFromPoints(points = [], fallback = { minX: -1000, maxX: 1000, minY: -1000, maxY: 1000 }) {
 20→  if (!points.length) return fallback;
 21→  return {
 22→    minX: Math.min(...points.map((point) => point.x)),
 23→    maxX: Math.max(...points.map((point) => point.x)),
 24→    minY: Math.min(...points.map((point) => point.y)),
 25→    maxY: Math.max(...points.map((point) => point.y)),
 26→  };
 27→}
 28→
 29→function expandBounds(bounds, paddingX, paddingY = paddingX) {
 30→  return {
 31→    minX: bounds.minX - paddingX,
 32→    maxX: bounds.maxX + paddingX,
 33→    minY: bounds.minY - paddingY,
 34→    maxY: bounds.maxY + paddingY,
 35→  };
 36→}
 37→
 38→function collectPlanPoints(floor) {
 39→  const points = [];
 40→
 41→  for (const wall of floor.walls || []) {
 42→    points.push(...(getWallRenderData(wall, floor.columns || []).outline || []));
 43→  }
 44→  for (const room of floor.rooms || []) {
 45→    points.push(...(room.points || []));
 46→  }
 47→  for (const beam of floor.beams || []) {
 48→    const renderData = getBeamRenderData(beam, floor.columns || []);
 49→    if (renderData?.outline) points.push(...renderData.outline);
 50→  }
 51→  for (const stair of floor.stairs || []) {
 52→    const renderData = getStairRenderData(stair);
 53→    if (renderData?.outline) points.push(...renderData.outline);
 54→  }
 55→  for (const landing of floor.landings || []) {
 56→    points.push(...landingOutline(landing));
 57→  }
 58→  for (const column of floor.columns || []) {
 59→    points.push(...columnOutline(column));
 60→  }
 61→  for (const slab of (floor.slabs || [])) {
 62→    const rd = getSlabRenderData(slab);
 63→    if (rd?.boundaryPoints) points.push(...rd.boundaryPoints);
 64→  }
 65→  for (const sc of (floor.sectionCuts || [])) {
 66→    points.push(sc.startPoint, sc.endPoint);
 67→    const renderData = getSectionCutRenderData(sc);
 68→    if (renderData?.arrow) {
 69→      points.push(renderData.arrow.shaftStart, renderData.arrow.shaftEnd, renderData.arrow.headA, renderData.arrow.headB);
 70→    }
 71→  }
 72→
 73→  for (const door of floor.doors || []) {
 74→    const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
 75→    if (!wall) continue;
 76→    const outline = doorOutlineOnWall(wall, door);
 77→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 78→  }
 79→
 80→  for (const windowItem of floor.windows || []) {
 81→    const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
 82→    if (!wall) continue;
 83→    const outline = windowOutlineOnWall(wall, windowItem);
 84→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 85→  }
 86→
 87→  for (const fixture of floor.fixtures || []) {
 88→    points.push(...fixtureOutline(fixture));
 89→  }
 90→
 91→  return points;
 92→}
