  82→function createImageFromSvgString(svgString) {
  83→  return new Promise((resolve, reject) => {
  84→    const blob = new Blob([svgString], { type: 'image/svg+xml;charset=utf-8' });
  85→    const url = URL.createObjectURL(blob);
  86→    const image = new Image();
  87→    image.onload = () => {
  88→      URL.revokeObjectURL(url);
  89→      resolve(image);
  90→    };
  91→    image.onerror = (error) => {
  92→      URL.revokeObjectURL(url);
  93→      reject(error);
  94→    };
  95→    image.src = url;
  96→  });
  97→}
