 649→
 650→  if (needsClip) {
 651→    const width = Number(element.getAttribute('width')) || 0;
 652→    const height = Number(element.getAttribute('height')) || 0;
 653→    builder.write(`0 0 ${fmt(width)} ${fmt(height)} re W n`);
