 771→function drawPathToCanvas(context, element) {
 772→  const style = computeStyle(element);
 773→  const commands = parsePathData(element.getAttribute('d') || '');
 774→  if (!commands.length) return;
 775→
 776→  context.save();
 777→  applyCanvasStyle(context, style);
 778→  context.beginPath();
 779→  for (const command of commands) {
 780→    if (command.type === 'M') context.moveTo(command.x, command.y);
 781→    else if (command.type === 'L') context.lineTo(command.x, command.y);
 782→    else if (command.type === 'Z') context.closePath();
 783→  }
 784→  fillAndStrokeCanvasPath(context, style);
 785→  context.restore();
 786→}
 787→
 788→function drawTextToCanvas(context, element) {
 789→  const style = computeStyle(element);
 790→  if (!style.fill) return;
 791→
 792→  context.save();
 793→  context.fillStyle = `rgb(${Math.round(style.fill[0] * 255)}, ${Math.round(style.fill[1] * 255)}, ${Math.round(style.fill[2] * 255)})`;
 794→  context.globalAlpha = style.fillOpacity;
 795→  context.font = `${style.fontWeight} ${style.fontSize}px ${style.fontFamily}`;
 796→  context.textAlign = style.textAnchor === 'middle' ? 'center' : style.textAnchor === 'end' ? 'right' : 'left';
 797→  context.textBaseline = style.dominantBaseline === 'middle' ? 'middle' : 'alphabetic';
 798→
 799→  const lines = getTextLines(element);
 800→  for (const line of lines) {
 801→    context.fillText(line.text, line.x, line.y);
 802→  }
 803→
 804→  context.restore();
 805→}
 806→
 807→function drawImageToCanvas(context, element, imageMap) {
 808→  const href = element.getAttribute('href') || element.getAttributeNS('http://www.w3.org/1999/xlink', 'href');
 809→  const entry = href && imageMap.get(href);
 810→  if (!entry) return;
 811→  const x = Number(element.getAttribute('x')) || 0;
 812→  const y = Number(element.getAttribute('y')) || 0;
 813→  const width = Number(element.getAttribute('width')) || entry.width;
 814→  const height = Number(element.getAttribute('height')) || entry.height;
 815→  context.drawImage(entry.img, x, y, width, height);
 816→}
 817→
 818→function drawElementToCanvas(context, element, imageMap) {
 819→  const tagName = element.tagName.toLowerCase();
 820→  beginCanvasNode(context, element);
 821→
 822→  switch (tagName) {
 823→    case 'svg':
 824→    case 'g':
 825→      [...element.children].forEach((child) => drawElementToCanvas(context, child, imageMap));
 826→      break;
 827→    case 'rect':
 828→      drawRectToCanvas(context, element);
 829→      break;
 830→    case 'line':
 831→      drawLineToCanvas(context, element);
 832→      break;
 833→    case 'polygon':
 834→      drawPolygonToCanvas(context, element, true);
 835→      break;
 836→    case 'polyline':
 837→      drawPolygonToCanvas(context, element, false);
 838→      break;
 839→    case 'path':
 840→      drawPathToCanvas(context, element);
 841→      break;
 842→    case 'text':
 843→      drawTextToCanvas(context, element);
 844→      break;
 845→    case 'image':
 846→      drawImageToCanvas(context, element, imageMap);
 847→      break;
 848→    default:
 849→      [...element.children].forEach((child) => drawElementToCanvas(context, child, imageMap));
 850→      break;
 851→  }
 852→
 853→  endCanvasNode(context);
 854→}
 855→
 856→function renderPolygonLike(builder, element, closePath) {
 857→  const points = parsePoints(element.getAttribute('points') || '');
 858→  if (!points.length) return;
 859→  const style = computeStyle(element);
 860→  builder.write('q');
 861→  builder.applyStyle(style);
 862→  emitPathFromPoints(builder, points, closePath);
 863→
 864→  if (style.fill && style.stroke && style.strokeWidth > 0) builder.write('B');
 865→  else if (style.fill) builder.write('f');
 866→  else if (style.stroke && style.strokeWidth > 0) builder.write('S');
 867→  builder.write('Q');
 868→}
 869→
 870→function renderRect(builder, element) {
 871→  const x = Number(element.getAttribute('x')) || 0;
 872→  const y = Number(element.getAttribute('y')) || 0;
 873→  const width = Number(element.getAttribute('width')) || 0;
 874→  const height = Number(element.getAttribute('height')) || 0;
 875→  const style = computeStyle(element);
 876→
 877→  builder.write('q');
 878→  builder.applyStyle(style);
 879→  builder.write(`${fmt(x)} ${fmt(y)} ${fmt(width)} ${fmt(height)} re`);
 880→  if (style.fill && style.stroke && style.strokeWidth > 0) builder.write('B');
 881→  else if (style.fill) builder.write('f');
 882→  else if (style.stroke && style.strokeWidth > 0) builder.write('S');
 883→  builder.write('Q');
 884→}
 885→
 886→function renderLine(builder, element) {
 887→  const x1 = Number(element.getAttribute('x1')) || 0;
 888→  const y1 = Number(element.getAttribute('y1')) || 0;
 889→  const x2 = Number(element.getAttribute('x2')) || 0;
 890→  const y2 = Number(element.getAttribute('y2')) || 0;
 891→  const style = computeStyle(element);
 892→  if (!style.stroke || style.strokeWidth <= 0) return;
 893→
 894→  builder.write('q');
 895→  builder.applyStyle(style, { fillAllowed: false, strokeAllowed: true });
 896→  builder.write(`${fmt(x1)} ${fmt(y1)} m`);
 897→  builder.write(`${fmt(x2)} ${fmt(y2)} l`);
 898→  builder.write('S');
 899→  builder.write('Q');
 900→}
 901→
 902→function renderPath(builder, element) {
 903→  const commands = parsePathData(element.getAttribute('d') || '');
 904→  if (!commands.length) return;
 905→  const style = computeStyle(element);
 906→
 907→  builder.write('q');
 908→  builder.applyStyle(style);
 909→  for (const command of commands) {
 910→    if (command.type === 'M') builder.write(`${fmt(command.x)} ${fmt(command.y)} m`);
 911→    else if (command.type === 'L') builder.write(`${fmt(command.x)} ${fmt(command.y)} l`);
 912→    else if (command.type === 'Z') builder.write('h');
 913→  }
 914→
 915→  if (style.fill && style.stroke && style.strokeWidth > 0) builder.write('B');
 916→  else if (style.fill) builder.write('f');
 917→  else if (style.stroke && style.strokeWidth > 0) builder.write('S');
 918→  builder.write('Q');
 919→}
 920→
 921→function estimateTextWidth(text, fontSize) {
 922→  return text.length * fontSize * 0.56;
 923→}
 924→
 925→function renderTextLine(builder, text, x, y, style) {
 926→  if (!text) return;
 927→  let drawX = x;
 928→  const textWidth = estimateTextWidth(text, style.fontSize);
 929→  if (style.textAnchor === 'middle') drawX -= textWidth / 2;
 930→  else if (style.textAnchor === 'end') drawX -= textWidth;
 931→
 932→  let baselineY = y;
 933→  if (style.dominantBaseline === 'middle') {
 934→    baselineY += style.fontSize * 0.32;
 935→  }
 936→
 937→  builder.write('q');
 938→  builder.applyStyle(style, { fillAllowed: true, strokeAllowed: false });
 939→  builder.write('BT');
 940→  builder.write(`/F1 ${fmt(style.fontSize)} Tf`);
 941→  builder.write(`1 0 0 -1 ${fmt(drawX)} ${fmt(baselineY)} Tm`);
 942→  builder.write(`(${escapePdfText(text)}) Tj`);
 943→  builder.write('ET');
 944→  builder.write('Q');
 945→}
 946→
 947→function getTextLines(element) {
 948→  const x = Number(element.getAttribute('x')) || 0;
 949→  const y = Number(element.getAttribute('y')) || 0;
 950→  const tspans = [...element.children].filter((child) => child.tagName?.toLowerCase() === 'tspan');
 951→
 952→  if (!tspans.length) {
 953→    return [{ text: element.textContent || '', x, y }];
 954→  }
 955→
 956→  let currentY = y;
 957→  return tspans.map((tspan, index) => {
 958→    const text = tspan.textContent || '';
 959→    const lineX = tspan.hasAttribute('x') ? Number(tspan.getAttribute('x')) : x;
 960→    if (tspan.hasAttribute('y')) {
 961→      currentY = Number(tspan.getAttribute('y'));
 962→    } else if (tspan.hasAttribute('dy')) {
 963→      currentY += Number(tspan.getAttribute('dy'));
 964→    } else if (index > 0) {
 965→      currentY = y;
 966→    }
 967→    return { text, x: lineX, y: currentY };
 968→  });
 969→}
 970→
 971→function renderText(builder, element) {
 972→  const style = computeStyle(element);
 973→  if (!style.fill) return;
 974→  const lines = getTextLines(element);
 975→  lines.forEach((line) => renderTextLine(builder, line.text, line.x, line.y, style));
 976→}
 977→
 978→function renderImage(builder, element, imageMap) {
 979→  const href = element.getAttribute('href') || element.getAttributeNS('http://www.w3.org/1999/xlink', 'href');
 980→  const entry = href && imageMap.get(href);
 981→  if (!entry) return;
 982→  const x = Number(element.getAttribute('x')) || 0;
 983→  const y = Number(element.getAttribute('y')) || 0;
 984→  const width = Number(element.getAttribute('width')) || entry.width;
 985→  const height = Number(element.getAttribute('height')) || entry.height;
 986→  const imgName = builder.addImage(entry.jpegBytes, entry.width, entry.height);
 987→  builder.write('q');
 988→  builder.write(`${fmt(width)} 0 0 ${fmt(-height)} ${fmt(x)} ${fmt(y + height)} cm`);
 989→  builder.write(`/${imgName} Do`);
 990→  builder.write('Q');
 991→}
 992→
 993→function walkElement(builder, element, imageMap) {
 994→  const tagName = element.tagName.toLowerCase();
 995→  const wrapped = beginNode(builder, element);
 996→
 997→  switch (tagName) {
 998→    case 'svg':
 999→    case 'g':
1000→      [...element.children].forEach((child) => walkElement(builder, child, imageMap));
1001→      break;
1002→    case 'rect':
1003→      renderRect(builder, element);
1004→      break;
1005→    case 'line':
1006→      renderLine(builder, element);
1007→      break;
1008→    case 'polygon':
1009→      renderPolygonLike(builder, element, true);
1010→      break;
1011→    case 'polyline':
1012→      renderPolygonLike(builder, element, false);
1013→      break;
1014→    case 'path':
1015→      renderPath(builder, element);
1016→      break;
1017→    case 'text':
1018→      renderText(builder, element);
1019→      break;
1020→    case 'image':
1021→      renderImage(builder, element, imageMap);
1022→      break;
1023→    default:
1024→      [...element.children].forEach((child) => walkElement(builder, child, imageMap));
1025→      break;
1026→  }
1027→
1028→  endNode(builder, wrapped);
1029→}
