116→function AppInner() {
117→  const { project, isDirty, dispatch } = useProject();
118→  const orderedFloors = useMemo(() => getOrderedFloors(project), [project]);
119→  const availableFloorIds = useMemo(() => orderedFloors.map((floor) => floor.id), [orderedFloors]);
120→  const initialActiveFloorId = getDefaultActiveFloorId(project);
121→  const [showLoadModal, setShowLoadModal] = useState(false);
122→  const [savedProjects, setSavedProjects] = useState([]);
123→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
124→  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
125→  const [projectFileHandle, setProjectFileHandle] = useState(null);
126→  const importInputRef = useRef(null);
127→
128→  useAutosave(project, isDirty, dispatch);
129→
130→  // beforeunload warning
131→  useEffect(() => {
132→    const handler = (e) => {
133→      if (isDirty) {
134→        e.preventDefault();
135→        e.returnValue = '';
136→      }
137→    };
138→    window.addEventListener('beforeunload', handler);
139→    return () => window.removeEventListener('beforeunload', handler);
140→  }, [isDirty]);
141→
142→  const handleNew = useCallback(() => {
143→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
144→    setProjectFileHandle(null);
145→    dispatch({ type: 'PROJECT_NEW', project: createProject() });
146→  }, [isDirty, dispatch]);
147→
148→  const handleSave = useCallback(async () => {
149→    try {
150→      const { fileHandle } = await exportProjectFile(project, { fileHandle: projectFileHandle });
151→      setProjectFileHandle(fileHandle);
152→      try {
153→        await saveProject(project);
154→      } catch {
155→        // Browser draft sync is secondary to file save.
156→      }
157→      dispatch({ type: 'MARK_SAVED' });
158→    } catch (err) {
159→      if (isFilePickerAbortError(err)) return;
160→      alert('Failed to save project file: ' + err.message);
161→    }
162→  }, [project, projectFileHandle, dispatch]);
163→
164→  // Ctrl+S save
165→  useEffect(() => {
166→    const handler = (e) => {
167→      if (isTypingTarget(e.target)) return;
168→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
169→        e.preventDefault();
170→        handleSave();
171→      }
172→    };
173→    window.addEventListener('keydown', handler);
174→    return () => window.removeEventListener('keydown', handler);
175→  }, [handleSave]);
176→
177→  const handleLoadClick = useCallback(async () => {
178→    setSavedProjects(await listProjects());
179→    setShowLoadModal(true);
180→  }, []);
181→
182→  const handleOpenProjectFile = useCallback(async () => {
183→    if (typeof window.showOpenFilePicker !== 'function') {
184→      importInputRef.current?.click();
185→      return;
186→    }
187→
188→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
189→      return;
190→    }
191→
192→    try {
193→      const { project: loaded, savedAt, fileHandle } = await openProjectFile();
194→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
195→      setProjectFileHandle(fileHandle);
196→      setShowLoadModal(false);
197→    } catch (err) {
198→      if (isFilePickerAbortError(err)) return;
199→      alert('Failed to import project file: ' + err.message);
200→    }
201→  }, [isDirty, dispatch]);
202→
203→  const handleImportFile = useCallback(async (e) => {
204→    const file = e.target.files?.[0] || null;
205→    e.target.value = '';
206→    if (!file) return;
207→
208→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
209→      return;
210→    }
211→
212→    try {
213→      const { project: loaded, savedAt } = await importProjectFile(file);
214→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
215→      setProjectFileHandle(null);
216→      setShowLoadModal(false);
217→    } catch (err) {
218→      alert('Failed to import project file: ' + err.message);
219→    }
220→  }, [isDirty, dispatch]);
221→
222→  const handleLoad = useCallback(async (id) => {
223→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
224→    try {
225→      const { project: loaded, savedAt } = await loadProject(id);
226→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
227→      setProjectFileHandle(null);
228→      setShowLoadModal(false);
229→    } catch (err) {
230→      alert('Failed to load project: ' + err.message);
231→    }
232→  }, [isDirty, dispatch]);
233→
234→  const handleDelete = useCallback(async (id, name) => {
235→    const confirmed = window.confirm(`Delete "${name}"? This cannot be undone.`);
236→    if (!confirmed) return;
237→
238→    try {
239→      await deleteProject(id);
240→      setSavedProjects(projects => projects.filter(project => project.id !== id));
241→    } catch (err) {
242→      alert('Failed to delete project: ' + err.message);
243→    }
244→  }, []);
245→
246→  return (
247→    <EditorProvider
248→      initialActiveFloorId={initialActiveFloorId}
249→      availableFloorIds={availableFloorIds}
250→    >
251→      <input
252→        ref={importInputRef}
253→        type="file"
254→        accept=".json,application/json"
255→        onChange={handleImportFile}
256→        style={{ display: 'none' }}
257→      />
258→
259→      <EditorShell
260→        project={project}
261→        handleNew={handleNew}
262→        handleSave={handleSave}
263→        handleLoadClick={handleLoadClick}
264→        isSidebarCollapsed={isSidebarCollapsed}
265→        isPropertiesCollapsed={isPropertiesCollapsed}
266→        onToggleSidebar={() => setIsSidebarCollapsed(value => !value)}
267→        onToggleProperties={() => setIsPropertiesCollapsed(value => !value)}
268→      />
269→
270→      {showLoadModal && (
271→        <Modal title="Open Project" onClose={() => setShowLoadModal(false)}>
272→          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
273→            <div className={modalStyles.modalCard}>
274→              <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
275→                <span className={modalStyles.modalCardTitle}>Project File</span>
276→                <span className={modalStyles.modalCardDesc}>
277→                  Open a JSON file previously saved to your computer.
278→                </span>
279→              </div>
280→              <button className={modalStyles.modalBtn} onClick={handleOpenProjectFile} style={{ alignSelf: 'flex-start' }}>
281→                Open Project File
282→              </button>
283→            </div>
284→
285→            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
286→              <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
287→                <span className={modalStyles.modalCardTitle}>Browser Drafts</span>
288→                <span className={modalStyles.modalCardDesc} style={{ fontSize: '11px' }}>
289→                  Stored only in this browser on this machine.
290→                </span>
291→              </div>
292→              {savedProjects.length === 0 ? (
293→                <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px', margin: 0 }}>
294→                  No browser drafts found.
295→                </p>
296→              ) : (
297→                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
298→                  {savedProjects.map(p => (
299→                    <div key={p.id} className={modalStyles.modalCard} style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
300→                      <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
301→                        <span style={{ fontWeight: 500, fontSize: '13px' }}>{p.name}</span>
302→                        <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
303→                          {new Date(p.savedAt).toLocaleDateString()}
304→                        </span>
305→                      </div>
306→                      <div style={{ display: 'flex', gap: '8px' }}>
307→                        <button className={modalStyles.modalBtn} onClick={() => handleLoad(p.id)}>Load</button>
308→                        <button className={modalStyles.modalBtnDanger} onClick={() => handleDelete(p.id, p.name)}>Delete</button>
309→                      </div>
310→                    </div>
311→                  ))}
312→                </div>
313→              )}
314→            </div>
315→          </div>
316→          <button className={modalStyles.modalBtn} onClick={() => setShowLoadModal(false)} style={{ marginTop: '16px' }}>
317→            Cancel
318→          </button>
319→        </Modal>
320→      )}
321→    </EditorProvider>
322→  );
323→}
