20→function rectPoints(bounds) {
21→  return [
22→    { x: bounds.minX, y: bounds.minY },
23→    { x: bounds.maxX, y: bounds.minY },
24→    { x: bounds.maxX, y: bounds.maxY },
25→    { x: bounds.minX, y: bounds.maxY },
26→  ];
27→}
28→
29→function pointInRect(point, bounds) {
30→  return point.x >= bounds.minX &&
31→    point.x <= bounds.maxX &&
32→    point.y >= bounds.minY &&
33→    point.y <= bounds.maxY;
34→}
