36→function segmentIntersectsRect(start, end, bounds) {
37→  if (pointInRect(start, bounds) || pointInRect(end, bounds)) return true;
38→
39→  const rect = rectPoints(bounds);
40→  for (let index = 0; index < rect.length; index += 1) {
41→    const hit = segmentIntersection(start, end, rect[index], rect[(index + 1) % rect.length]);
42→    if (hit) return true;
43→  }
44→
45→  return false;
46→}
