52→  const rect = rectPoints(bounds);
53→  if (rect.some((point) => pointInPolygon(point, points))) return true;
54→
55→  for (let index = 0; index < points.length; index += 1) {
56→    if (segmentIntersectsRect(points[index], points[(index + 1) % points.length], bounds)) {
57→      return true;
58→    }
59→  }
60→
61→  return false;
62→}
