64→function geometryIntersectsRect(geometry, bounds) {
65→  if (!geometry) return false;
66→  if (geometry.polygon) return polygonIntersectsRect(geometry.polygon, bounds);
67→  if (geometry.segments) {
68→    return geometry.segments.some((segment) => segmentIntersectsRect(segment.start, segment.end, bounds));
69→  }
70→  return false;
